  ('real-estate-moex-02362', 'real-estate', 'real-estate-moex-098-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '建物因功能或效益衰退至不值得使用所經歷之年數稱為：', '["實體耐用年數", "經濟耐用年數", "物理耐用年數", "實際經歷年數"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "527a4d0d6787", "answer_pdf_sha1": "a96275b29124", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產估價概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02363', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '下列對於定型化契約中條款的敘述，何者錯誤？', '["定型化契約條款如有疑義時，應為有利於消費者之解釋", "契約之主要權利或義務，因受條款之限制，致契約之目的難以達成者，對消費者顯失公平，契約無效", "定型化契約中之定型化契約條款牴觸個別磋商條款之約定者，其牴觸部分，應以定型化契約條款為有效", "定型化契約條款雖未經記載於定型化契約中者，由企業經營者向消費者明示其內容，並經消費者同意 受其拘束者，該條款即為契約之內容"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02364', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '消費者郵購之商品，如果不願買受時，得於收受商品後幾日內，退回商品，無須說明理由及負擔任何費 用或價款？', '["七日", "十日", "十五日", "三十日"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02365', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '神童雜誌社在消費者未訂閱前，即將雜誌郵寄給消費者閱讀，並言明滿意後再訂閱。但是消費者不願訂 閱時，對於該雜誌的處理下列敘述何者錯誤？', '["消費者不負保管義務", "消費者定相當期限通知取回而逾期未取回或無法通知者，視為神童雜誌社拋棄其寄投之雜誌", "在寄送後逾一個月未經消費者表示承諾，而仍不取回其雜誌者，視為拋棄其寄投之雜誌", "消費者不願訂閱時，寄回雜誌的郵資由消費者負擔"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02366', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '消費者向廠商分期付款購買機車，若在契約書中未約定利率，其利率按現金交易價格週年利率百分之多 少計算之？', '["百分之三", "百分之五", "百分之七", "百分之十"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02367', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '下列對於消費者資訊的敘述，何者錯誤？', '["某減肥藥品廠商廣告不實，為該廠商刊登廣告之媒體經營者明知廣告內容與事實不符者，就消費者因 信賴該廣告所受之損害也須與企業經營者負連帶責任", "某進口食品的外包裝已經加註安全警語，輸入後的中文標示就可以不必重複標示", "企業經營者對消費者保證商品之品質時，即使消費者不要求，也應主動出具書面保證書", "企業經營者對於所提供之商品應按其性質及交易習慣，不得誇張其內容或為過大之包裝"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02368', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '企業經營者若未依商品標示法等法令為商品進行標示，經主管機關通知改正而逾期不改正者，得處新臺 幣多少金額的罰鍰？', '["一萬元以上十萬元以下", "二萬元以上二十萬元以下", "三萬元以上三十萬元以下", "五萬元以上五十萬元以下"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02369', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '直轄市或縣（市）政府對於企業經營者提供之商品，經過調查，認為確有損害消費者的健康，應命其限期 回收或銷燬，如果企業違反此規定者，得處新臺幣多少金額的罰鍰？', '["二萬元以上二十萬元以下", "三萬元以上三十萬元以下", "五萬元以上五十萬元以下", "六萬元以上一百五十萬元以下"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02370', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '關於消費爭議之調解，當事人不能合意但已甚接近者，調解委員得斟酌一切情形，求兩造利益之平衡， 於不違反兩造當事人之主要意思範圍內，依職權提出解決事件之方案，並送達於當事人。當事人若有異 議，得於通知送達後幾日之不變期間內提出異議，否則，視為該方案已調解成立？', '["十日", "十五日", "二十日", "三十日"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02371', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '消費者與企業經營者因商品或服務發生消費爭議時，關於爭議的解決方式下列何者錯誤？', '["消費者得向企業經營者或消費者保護團體申訴", "消費者向企業經營者申訴，未獲妥適處理時，得向直轄市、縣（市）政府消費者保護官申訴", "消費者向直轄市、縣（市）政府消費者保護官申訴，未獲妥適處理時，得向直轄市或縣（市）消費爭 議調解委員會申請調解", "消費者向直轄市或縣（市）消費爭議調解委員會申請調解，未獲妥適處理時，始得向法院提起消費訴訟"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
